import torch
def rot_trans_geo(geometry, rot, trans):
    import torch
    def rot_trans_geo(geometry, rot, trans):
        rotted = torch.einsum('bij,bnj->bni', rot, geometry)
        return rotted + trans.unsqueeze(1)

