import torch
def rot_trans_geo(geometry, rot, trans):
    import torch
    def rot_trans_geo(geometry, rot, trans):
        B, N, _ = geometry.shape
        rot_exp = rot.unsqueeze(1).expand(-1, N, -1, -1).reshape(B * N, 3, 3)
        geom_col = geometry.reshape(B * N, 3, 1)
        out = torch.bmm(rot_exp, geom_col).reshape(B, N, 3)
        return out + trans.unsqueeze(1)

