import torch
def rot_trans_geo(geometry, rot, trans):
    import torch
    def rot_trans_geo(geometry, rot, trans):
        outs = []
        for r, g, t in zip(rot, geometry, trans):
            out = (r @ g.T).T + t
            outs.append(out)
        return torch.stack(outs, dim=0)

