import torch
def rot_trans_geo(geometry, rot, trans):
    import torch
    def rot_trans_geo(geometry, rot, trans):
        rot_exp = rot.unsqueeze(1)
        g_uns = geometry.unsqueeze(-1)
        rotated = (rot_exp * g_uns).sum(-1)
        return rotated + trans.unsqueeze(1)

