def unsafeSub(x, y):
    BITS = 32
    BYTES = BITS // 8
    MOD = 1 << BITS
    def unsafeSub(x, y):
        val = (int(x) - int(y)) % MOD
        return int.from_bytes(val.to_bytes(BYTES, "little", signed=False), "little")
